require "data.GameTask"

TaskController = class()

function TaskController:ctor(player)
    self.userId = player.userId
    self.dailyTasks = {}
    self.mainLineTasks = {}
end

function TaskController:init()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    if DbUtil:IsGetAllDataFinished(player) then
        self.unlock_level = player.unlock_level
        self:initDailyTasks(player)
        self:initMainLineTasks(player)
        self:initActiveInfo()
        self:consumeTaskProcesses(player)
        self:unlockMainLineTask(player)
        self:packingAchievementData(player)
        self:sendMainLineTaskToClient()
        self:sendDailyTaskToClient()
    end
end

function TaskController:initDailyTasks(player)
    self.dailyTasks = {}
    local daily_tasks = player.daily_tasks
    for _, task in pairs(daily_tasks) do
        self:addDailyTask(GameTask.new(player.userId, task.id, Define.TaskMain.Daily, task.progress, task.status))
    end
end

function TaskController:initMainLineTasks(player)
    self.mainLineTasks = {}
    local mainline_tasks = player.mainline_tasks
    for _, task in pairs(mainline_tasks) do
        self:addMainLineTask(GameTask.new(player.userId, task.id, Define.TaskMain.Mainline, task.progress, task.status))
    end
end

function TaskController:resetDailyTasks()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    self.dailyTasks = {}
    local pLevel = player.level
    local levelGroup = TaskConfig:getTaskDailyGroup(pLevel)[1]
    if levelGroup == nil then
        return
    end
    --init regular task's list
    local mainTaskIds = TaskPoolManager:getTaskIdsFromRegularPool(levelGroup.MainPoolId)
    for _, taskId in pairs(mainTaskIds) do
        self:addDailyTask(GameTask.new(player.userId, taskId, Define.TaskMain.Daily))
    end

    --init random task's list
    local randomTaskIds = TaskPoolManager:getTaskIdsFromRandomPool(levelGroup.RandomPoolId, levelGroup.TaskCount)
    for _, taskId in pairs(randomTaskIds) do
        self:addDailyTask(GameTask.new(player.userId, taskId, Define.TaskMain.Daily))
    end
end

function TaskController:unlockMainLineTask(player)
    if player.level <= player.unlock_level then
        player.unlock_level = player.level
        self.unlock_level = player.level
        return
    end
    local pLevel = player.level
    local Groups = TaskConfig:getTaskMainGroup(pLevel, player.unlock_level)
    local tasks = {}
    for _, group in pairs(Groups) do
        local taskIds = TaskPoolManager:getTaskIdsFromRegularPool(group.MainPoolId)
        for _, taskId in pairs(taskIds) do
            self:addMainLineTask(GameTask.new(player.userId, taskId, Define.TaskMain.Mainline))
            table.insert(tasks, { Id = taskId, CurNum = 0, Status = GameTask.TaskStatus.PROGRESSING })
        end
    end
    player.unlock_level = pLevel
    self.unlock_level = pLevel
    if #tasks > 0 then
        GamePacketSender:sendPixelGunMainLineTaskData(player.rakssid, self.unlock_level, json.encode(tasks))
        self:packingAchievementData(player)
    end
end

function TaskController:packingAchievementData(player)
    self:packingProgressData(player, Define.TaskType.GrowUp.Online, GameMatch.gameType, nil, 0)
    self:packingProgressData(player, Define.TaskType.Achievement.PlayerLevel, GameMatch.gameType, nil, player.level)
    self:packingProgressData(player, Define.TaskType.Achievement.ArmorLevel, GameMatch.gameType, nil, player.armor_level)
    for _, player_gun in pairs(player.guns) do
        if player_gun.Status == GameGunStore.Status.HAS_GET or player_gun.Status == GameGunStore.Status.HAS_USE then
            local config = GunConfig:getGun(player_gun.Id)
            if config then
                self:packingProgressData(player, Define.TaskType.Achievement.EquipLevel, GameMatch.gameType, config.ItemId, player_gun.Level)
            end
        end
    end
    for _, player_prop in pairs(player.props) do
        if player_prop.Status == GameGunStore.Status.HAS_GET or player_prop.Status == GameGunStore.Status.HAS_USE then
            local config = PropConfig:getProp(player_prop.Id)
            if config then
                self:packingProgressData(player, Define.TaskType.Achievement.EquipLevel, GameMatch.gameType, config.ItemId, player_prop.Level)
            end
        end
    end
    for _, player_block in pairs(player.blocks) do
        if player_block.Status == GameGunStore.Status.HAS_GET or player_block.Status == GameGunStore.Status.HAS_USE then
            local config = PropConfig:getProp(player_block.Id)
            if config then
                self:packingProgressData(player, Define.TaskType.Achievement.EquipLevel, GameMatch.gameType, config.ItemId, player_block.Level)
            end
        end
    end
end

function TaskController:packingProgressData(player, taskTypeId, gameType, remarks, value)
    local data = {
        Type = taskTypeId,
        GameType = gameType,
        Remarks = remarks,
        Value = value or 1
    }
    self:consumeTaskProcess(data)
end

function TaskController:saveTaskProcesses(player, progress)
    table.insert(player.task_progresses, progress)
end

function TaskController:consumeTaskProcesses(player)
    local progresses = player.task_progresses
    for key, progress in pairs(progresses) do
        self:consumeTaskProcess(progress)
    end
    player.task_progresses = {}
end

function TaskController:consumeTaskProcess(progress)
    for _, task in pairs(self.dailyTasks) do
        if GameTask.TaskStatus.PROGRESSING == task.status or (GameTask.TaskStatus.FINISHED == task.status and task.nextTaskId ~= 0) then
            task:matching(progress)
        end
    end
    for _, task in pairs(self.mainLineTasks) do
        if GameTask.TaskStatus.PROGRESSING == task.status or (GameTask.TaskStatus.FINISHED == task.status and task.nextTaskId ~= 0) then
            task:matching(progress)
        end
    end
end

function TaskController:sendDailyTaskToClient()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local tasks = {}
    for _, task in pairs(self.dailyTasks) do
        table.insert(tasks, { Id = task.taskId, CurNum = task.progress, Status = task.status })
    end
    GamePacketSender:sendPixelGunDailyTaskData(player.rakssid, json.encode(tasks))
end

function TaskController:sendMainLineTaskToClient()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local tasks = {}
    for _, task in pairs(self.mainLineTasks) do
        if task.status ~= GameTask.TaskStatus.RECEIVED then
            table.insert(tasks, { Id = task.taskId, CurNum = task.progress, Status = task.status })
        end
    end
    GamePacketSender:sendPixelGunMainLineTaskData(player.rakssid, self.unlock_level, json.encode(tasks))
end

function TaskController:addDailyTask(task)
    for _, record in pairs(self.dailyTasks) do
        if record.taskId == task.taskId then
            return
        end
    end
    table.insert(self.dailyTasks, task)
end

function TaskController:addMainLineTask(task)
    for _, record in pairs(self.mainLineTasks) do
        if record.taskId == task.taskId then
            return
        end
    end
    table.insert(self.mainLineTasks, task)
end

function TaskController:transformToPlayerTaskData(player)
    local dailyTasksData = {}
    for _, task in pairs(self.dailyTasks) do
        table.insert(dailyTasksData, { id = task.taskId, progress = task.progress, status = task.status })
    end
    player.daily_tasks = dailyTasksData

    local mainlineTasksData = {}
    for _, task in pairs(self.mainLineTasks) do
        if task.status ~= GameTask.TaskStatus.RECEIVED then
            table.insert(mainlineTasksData, { id = task.taskId, progress = task.progress, status = task.status })
        end
    end
    player.mainline_tasks = mainlineTasksData
end

function TaskController:getActiveInfo()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    if TableUtil.isEmpty(player.active_info) then
        player.active_info = {
            Day = {
                Key = "",
                Value = 0,
                Records = {}
            },
            Week = {
                Key = "",
                Value = 0,
                Records = {}
            }
        }
    end
    return player.active_info
end

function TaskController:initActiveInfo()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local active_info = self:getActiveInfo()
    local dayId = DateUtil.getYearDay()
    local weekId = DateUtil.getYearWeek()
    if active_info.Day.Key ~= dayId then
        self:resetDailyTasks()
        active_info.Day.Key = dayId
        active_info.Day.Value = 0
        active_info.Day.Records = {}
    end
    if active_info.Week.Key ~= weekId then
        active_info.Week.Key = weekId
        active_info.Week.Value = 0
        active_info.Week.Records = {}
    end
    for _, activeId in pairs(active_info.Day.Records) do
        GamePacketSender:sendPixelGunTaskActiveStatus(player.rakssid, activeId, Define.TaskActiveStatus.Received)
    end
    for _, activeId in pairs(active_info.Week.Records) do
        GamePacketSender:sendPixelGunTaskActiveStatus(player.rakssid, activeId, Define.TaskActiveStatus.Received)
    end
    self:sendActiveTime()
    self:sendActiveValue()
end

function TaskController:addActiveValue(value)
    local active_info = self:getActiveInfo()
    active_info.Day.Value = active_info.Day.Value + value
    active_info.Week.Value = active_info.Week.Value + value
    self:sendActiveValue()
end

function TaskController:sendActiveValue()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local active_info = self:getActiveInfo()
    GamePacketSender:sendPixelGunTaskActiveValue(player.rakssid, Define.TaskActiveType.Day, active_info.Day.Value)
    GamePacketSender:sendPixelGunTaskActiveValue(player.rakssid, Define.TaskActiveType.Week, active_info.Week.Value)
end

function TaskController:sendActiveTime()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local time = os.time()
    GamePacketSender:sendPixelGunTaskActiveTime(player.rakssid, Define.TaskActiveType.Day, DateUtil.getDayLastTime(nil, true) - time)
    GamePacketSender:sendPixelGunTaskActiveTime(player.rakssid, Define.TaskActiveType.Week, DateUtil.getWeekLastTime(nil, true) - time)
end

function TaskController:onReceiveActiveRewards(activeId)
    local active_info = self:getActiveInfo()
    local active = TaskActiveConfig:getTaskActive(activeId)
    if not active then
        return
    end
    local info
    local key
    if active.Type == Define.TaskActiveType.Day then
        info = active_info.Day
        key = DateUtil.getYearDay()
    else
        info = active_info.Week
        key = DateUtil.getYearWeek()
    end
    if info.Key ~= key then
        return
    end
    for _, record in pairs(info.Records) do
        if record == activeId then
            return
        end
    end
    if info.Value < active.ActiveValue then
        return
    end
    table.insert(info.Records, activeId)
    self:doRewards(active.RewardIds)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    ReportUtil:reportActiveReceive(player, activeId)
end

function TaskController:receiveTaskReward(player, taskId)
    local task = self:getTaskByTaskId(taskId)
    if task then
        task:receiveTaskReward(player)
    end
end

function TaskController:receiveTaskDoubleReward(taskId)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local task = self:getTaskByTaskId(tonumber(taskId))
    if task then
        task:receiveTaskDoubleReward(player)
    end
end

function TaskController:doRewards(rewardIds)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    for _, Id in pairs(rewardIds) do
        local reward = RewardConfig:getRewardById(tonumber(Id))
        if not reward then
            return
        end
        GameReward:onPlayerGetReward(player, reward)
    end
end

function TaskController:getTaskByTaskId(taskId)
    for _, task in pairs(self.dailyTasks) do
        if task.taskId == taskId then
            return task
        end
    end
    for _, task in pairs(self.mainLineTasks) do
        if task.taskId == taskId then
            return task
        end
    end
    return nil
end

return TaskController